201→
202→  // ── Tab switching ──
203→
204→  function switchTab(tab) {
205→    document.querySelectorAll('.tab').forEach(function(t) { t.classList.remove('active'); });
206→    document.querySelectorAll('.tab-content').forEach(function(t) { t.classList.remove('active'); });
207→    document.querySelector('[data-tab="' + tab + '"]').classList.add('active');
208→    document.getElementById('tab-' + tab).classList.add('active');
