252→    loadLanguages();
253→    loadSyncLog();
254→  }
255→
256→  function loadContentTypes() {
257→    startLoad();
258→    google.script.run
259→      .withSuccessHandler(function(types) {
260→        var sel = document.getElementById('contentType');
261→        sel.innerHTML = '<option value="">-- Select --</option>';
262→        types.forEach(function(ct) {
263→          var opt = document.createElement('option');
264→          opt.value = ct.variable;
265→          opt.textContent = ct.name;
266→          sel.appendChild(opt);
267→        });
268→        // Auto-select content type from metadata table
269→        google.script.run
270→          .withSuccessHandler(function(fields) {
271→            if (!fields) { endLoad(); return; }
272→            var found = false;
273→            for (var i = 0; i < fields.length; i++) {
274→              if (fields[i].variable === 'contentType' && fields[i].value) {
275→                sel.value = fields[i].value;
