/**
 * Extract a contentlet from the various response shapes dotCMS returns.
 * Shape 1: { identifier: "...", ... }
 * Shape 2: { results: [{ identifier: "..." }] }
 * Shape 3: { "<identifier>": { ... }, results: [...], ... }
 */
_extractContentlet: function (entity) {
  if (!entity) return {};

  // Shape 1: entity IS the contentlet
  if (entity.identifier) return entity;

  // Shape 2: results array with contentlet inside
  if (entity.results && entity.results.length > 0 && entity.results[0].identifier) {
    return entity.results[0];
  }

  // Shape 3: identifier-keyed — skip known metadata keys
  var skip = { errors: 1, messages: 1, results: 1, i18nMessagesMap: 1, pagination: 1, permissions: 1 };
  var keys = Object.keys(entity);
  for (var i = 0; i < keys.length; i++) {
    if (!skip[keys[i]]) {
      var val = entity[keys[i]];
      if (val && typeof val === 'object' && !Array.isArray(val)) {
        val.identifier = val.identifier || keys[i];
        return val;
      }
      // Key itself is the identifier
      return { identifier: keys[i] };
    }
  }

  return entity;
},

